export const UNIFESP_2024_QUESTIONS: any[] = [
  { id: "unifesp_2024_001", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 65 anos de idade, em exame de rotina apresenta dilatação aneurismática sacular de aorta abdominal com diâmetro transverso máximo ao ultrassom de 3 cm e 3 cm de extensão. O aneurisma se encontra a 2 centímetros abaixo das artérias renais. Paciente assintomático sem outras comorbidades. Qual é a conduta mais adequada?", options: ["Acompanhamento seriado.", "Enxerto aorto bifemoral com prótese de dacron.", "Tratamento cirúrgico endovascular.", "Embolização com fibrina intra aneurismática."], correctIndex: 2 },
  { id: "unifesp_2024_002", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Mulher, 27 anos de idade, submeteu-se à colecistectomia por via laparoscópica, sob ventilação mecânica. Durante a manutenção da anestesia observa-se, na capnografia, queda progressiva do CO2 expirado sem deformação da curva. Qual é o diagnóstico mais provável?", options: ["Insuflação excessiva do pneumoperitônio.", "Diminuição da pressão arterial.", "Aumento de resistência em vias aéreas.", "Recuperação do bloqueio neuromuscular."], correctIndex: 1 },
  { id: "unifesp_2024_003", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Homem, 75 anos de idade, será submetido a colectomia direita videolaparoscópica devido a tumor de cólon. Apresenta história de infarto do miocárdio tratado com colocação de stent. Os exames pré-operatórios demonstram PA = 110/55 mmHg, FC = 58 bpm, SatO2 = 96%. Ecocardiograma transtorácico apresentando FE 32%. Qual é hipnótico adequado para a indução da anestesia geral?", options: ["Propofol.", "Midazolam.", "Etomidato.", "Cetamina."], correctIndex: 2 },
  { id: "unifesp_2024_004", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 35 anos de idade, é admitido no PS, vítima de queimadura térmica de segundo grau, extensa, no antebraço e terço distal do membro superior direito. A lesão é caracterizada por bolhas, vermelhidão intensa e dor local. Qual é a conduta inicial mais adequada?", options: ["Cobertura da lesão com curativo estéril.", "Imersão do membro em água fria.", "Aplicação de pomada antibiótica sobre a lesão.", "Aplicação de pomada anestésica sobre a lesão."], correctIndex: 1 },
  { id: "unifesp_2024_005", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 63 anos de idade, apresenta lesão de 7mm na região centro-lateral da fronte, com diagnóstico de carcinoma basocelular. Indicada ressecção com margem de segurança por incisão fusiforme e fechamento primário. Seguindo os princípios das \"linhas de Langer\", qual é a melhor orientação da incisão?", options: ["Horizontal.", "Oblíqua direita.", "Oblíqua esquerda.", "Vertical."], correctIndex: 0 },
  { id: "unifesp_2024_006", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 68 anos de idade, encontra-se em pósoperatório de cirurgia de revascularização miocárdica, sem intercorrências, com ecocardiograma mostrando função ventricular normal e discreto derrame pleural à radiografia de tórax. Quais medicações devem ser continuadas após alta hospitalar?", options: ["Betabloqueador, estatina, AAS e diurético.", "Clopidogrel, AAS, inibidor da enzima de conversão da angiotensina e diurético.", "Betabloqueador, inibidor da enzima de conversão da angiotensina, estatina e AAS.", "Estatina, inibidor de enzima de conversão da angiotensina, AAS e clopidogrel."], correctIndex: 2 },
  { id: "unifesp_2024_007", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 38 anos de idade, apresenta dor abdominal há 3 dias, com intensidade progressiva, no hipocôndrio direito, irradiada para região interescapular, acompanhada de náuseas e vômitos. Refere episódio de febre não mensurada e escurecimento de urina. Exame físico: REG, FC = 95 bpm, PA = 130/80 mm Hg, T = 39 ºC, sudoreica, ictéricia = 1+/4+, dor à palpação do hipocôndrio direito e ausência de sinais de irritação peritoneal. Exame laboratorial: glicemia = 100 mg/dL, creatinina = 0,6, bilirrubina total = 2,8 (2,2 de direta) e leucocitose = 18.300 /mm3. Ultrassonografia abdominal: vesícula biliar normodistendida, paredes finas, cálculos móveis no seu interior, colédoco com 0,8 mm de diâmetro, colédoco distal de difícil avaliação. Pelos critérios de Tokyo 2018 esta paciente apresenta:", options: ["Colangite aguda grau I.", "Colangite aguda grau IV.", "Colangite aguda grau II.", "Colangite aguda grau III."], correctIndex: 2 },
  { id: "unifesp_2024_008", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 25 anos de idade, vítima de acidente motociclístico, dá entrada no PS com politraumatismo. Exame físico: pressão arterial 90/50 mmHg, frequência cardíaca = 115 bpm, frequência respiratória = 25 irpm, murmúrio vesicular abolido à direita, fratura exposta de fêmur à direita com grande desvio. Escala de coma de Glasgow 10. Baseado no diagnóstico com risco iminente à vida do paciente, qual é a primeira conduta?", options: ["Punção pericárdica.", "Intubação oro traqueal.", "Drenagem pleural à direita.", "Protocolo de transfusão maciça."], correctIndex: 2 },
  { id: "unifesp_2024_009", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 60 anos de idade, refere diminuição do jato urinário, noctúria 2 x, esforço miccional, sensação de esvaziamento vesical incompleto, há 6 meses. Qual é a propedêutica e a terapêutica iniciais para o diagnóstico mais provável?", options: ["Ultrassonografia; betanecol.", "Toque retal; betanecol.", "Toque retal; alfa bloqueador.", "Ultrassonografia; alfa bloqueador."], correctIndex: 2 },
  { id: "unifesp_2024_010", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Mulher, 32 anos de idade, deu entrada no Pronto Socorro com quadro de febre, dor lombar, há 24 horas, exame de urina com leucocitúria. Qual é a conduta baseada no diagnóstico mais provável?", options: ["Ureterolitotripsia.", "Passagem de cateter duplo J.", "Antibioticoterapia endovenoso com cobertura para gram(-).", "Antibioticoterapia oral com cobertura para gram(-)."], correctIndex: 2 },
  { id: "unifesp_2024_011", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 43 anos de idade, IMC 46 kg/m2, diabética, hipertensa, no quinto pós-operatório de Bypass gástrico em Y-de-Roux, apresenta inapetência e dor abdominal no epigástrio que piora à palpação. Exame físico: rebaixamento de nível de consciência, desidratada ++, FC: 110 bpm, PA: 100x60 mm Hg, FR: 22 irpm, SpO2 94% em ar ambiente. Qual é o diagnóstico mais provável?", options: ["Deiscência do pouch gástrico.", "Tromboembolismo pulmonar.", "Colecistite aguda alitiásica.", "Colite pseudomembranosa."], correctIndex: 0 },
  { id: "unifesp_2024_012", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 72 anos de idade, refere que há 6 meses notou aumento no número de evacuações, com consistência variável a depender da dieta, sem muco ou sangue visível. Negava dor abdominal e distensão, referia perda de peso de 7 kg no período. Exame físico: descorada 2+/4+, acianótica, anictérica, afebril, IMC = 35 kg/m2; abdome globoso, flácido, doloroso à palpação profunda de fossa ilíaca direita. Exames Laboratoriais: Hb = 6,9 (12,0-15,5), HCM = 23,9 (26-34) e VCM = 75 (82-98), ferritina = 250 (12-266), ferro = 100 (33-193). Qual é o diagnóstico mais provável?", options: ["Doença de Crohn de íleo terminal.", "Adenocarcinoma do cólon direito.", "Doença diverticular do cólon.", "Tumor neuroendócrino de apêndice."], correctIndex: 1 },
  { id: "unifesp_2024_013", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Homem, 67 anos de idade, tabagista 50 anosmaço, assintomático, submeteu-se à tomografia de tórax que evidenciou nódulo de 15 mm no lobo superior direito, sólido e espiculado. Biópsia transtorácica: adenocarcinoma invasivo, primário de pulmão. PET-Scan: captação no nódulo pulmonar de 12,4 SUV e linfonodos paratraqueais ipsilaterais de 6,7 SUV. Qual é a conduta mais adequada?", options: ["Quimioterapia e radioterapia.", "Pneumonectomia para ressecção oncológica completa.", "Biópsia dos linfonodos mediastinais.", "Ablação da lesão pulmonar por radiofrequência."], correctIndex: 2 },
  { id: "unifesp_2024_014", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Oncologia", text: "Homem, 28 anos de idade, apresenta edema cervicofacial matinal, tontura e cefaleia de início recente há 10 dias. Exame físico: corado, hidratado eupneico, PA = 120/70 mmHg, telangiectasias na parede torácica anterior, murmúrio vesicular presente e simétrico bilateral, sem ruídos adventícios. Fundo de olho: edema de papila. Exame neurológico normal. Qual é o diagnóstico sindrômico, possível causa e tratamento?", options: ["Síndrome de hipertensão intracraniana – câncer de pulmão – radioterapia.", "Síndrome da veia cava superior – linfoma mediastinal – quimioterapia.", "Síndrome de Cushing – linfoma – cirurgia descompressiva.", "Pericardite restritiva – tuberculose – cirurgia."], correctIndex: 1 },
  { id: "unifesp_2024_015", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 45 anos de idade, vítima de queda de telhado (6 metros) há 1 hora, dá entrada na sala de emergência de um hospital especializado em trauma. Apresentava índice de choque de 1,2 na entrada, mantido em 0,7 após infusão de 500 ml de cristalóide e 1 concentrado de hemácias. Exame físico: abdome pouco distendido, doloroso no hipocôndrio esquerdo, com líquido livre no espaço hepatorrenal. Tomografia de abdome com contraste intravenoso: pequena quantidade de líquido livre em pelve e hipocôndrios, associada à laceração esplênica de 2 cm no polo inferior, sem sinais de extravasamento ativo de contraste, fístula artériovenosa ou pseudoaneurisma. Qual é a conduta mais adequada?", options: ["Arteriografia com embolização", "Observação em UTI.", "Esplenectomia total.", "Esplenectomia parcial."], correctIndex: 1 },
  { id: "unifesp_2024_016", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 65 anos de idade, diabético, tabagista, apresenta disfunção erétil há um ano. Qual é o tratamento mais indicado?", options: ["Alfa bloqueador.", "Inibidor da 5-alfa-redutase.", "Inibidor da fosfodiesterase tipo 5.", "Lepidium meyenii."], correctIndex: 2 },
  { id: "unifesp_2024_017", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Pediátrica", text: "Menino, 6 anos de idade, apresenta dor abdominal em cólica e vômitos há 12 horas que evoluiu com distensão abdominal e evacuação muco sanguinolenta, há 2 horas. Realizou USG abdominal que mostrou imagem em \"alvo\" na fossa ilíaca direita. Qual é a conduta imediata mais adequada?", options: ["Correção hidroeletrolítica e metabólica.", "Tomografia computadorizada de abdome.", "Enema opaco com contraste não iônico isoosmolar.", "Redução hidrostática com auxílio da radiologia."], correctIndex: 0 },
  { id: "unifesp_2024_018", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Mulher, 22 anos de idade, vítima de acidente motociclístico, apresenta avulsão traumática da raiz de C6 a direita. Qual é a localização do déficit sensitivo e motor?", options: ["Face medial do antebraço e extensores do punho.", "Face lateral do antebraço e flexores do punho.", "Face lateral do antebraço e extensores do punho.", "Face medial do antebraço e flexores do punho."], correctIndex: 2 },
  { id: "unifesp_2024_019", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Pediátrica", text: "Recém-nascido, Apgar 9 e 10, apresenta vômitos biliosos e distensão abdominal ao terceiro dia de vida. Repentinamente teve comprometimento importante do estado geral, necessitando de intubação e drogas vasoativas. O abdome, previamente flácido e indolor, ficou distendido e doloroso. Quais são os diagnósticos mais prováveis?", options: ["Suboclusão duodenal; atresia jejuno-ileal.", "Volvo intestinal; enterocolite necrosante.", "Estenose hipertrófica do piloro; atresia pilórica.", "Megacólon congênito; síndrome da rolha meconial."], correctIndex: 1 },
  { id: "unifesp_2024_020", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Homem, 68 anos de idade, apresenta dor na região inguinal direita há 4 anos, sem história de trauma. O quadro teve início insidioso e piora progressiva e, no momento, paciente apresenta limitação para vestir meias e sapatos, além de dor noturna e no repouso. Radiografia da bacia evidencia redução do espaço articular no quadril direito, além de esclerose subcondral e osteófitos marginais. Realiza tratamento fisioterápico e utiliza antinflamatórios e opioides, diariamente, por mais de 6 meses. Qual é o diagnóstico mais provável e a conduta mais adequada?", options: ["Osteonecrose da cabeça femoral; artroplastia parcial do quadril.", "Fratura da cabeça femoral; osteossíntese do quadril.", "Osteoporose; prescrição de vitamina D e cálcio.", "Osteoartrite degenerativa; artroplastia total do quadril."], correctIndex: 3 },
  { id: "unifesp_2024_021", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Mulher, 88 anos de idade, tem diagnóstico de demência moderada e apresenta episódios de delírios e agitação psicomotora. Vem em consulta médica de rotina acompanhada do seu filho, que apresenta sinais de sobrecarga do cuidado e, em um instante de desentendimento com a mãe, ameaça institucionalizá-la. Diante deste caso de violência psicológica, assinale a alternativa correta.", options: ["A notificação de violência neste caso é desnecessária, pois trata-se de caso suspeito.", "Caracteriza-se a percepção de estresse do cuidador pela idosa com o Caregiver Abuse Screen.", "O estresse do cuidador é fator de risco para violência contra a pessoa idosa.", "A comunicação à autoridade policial é facultativa, pois não há risco iminente de morte."], correctIndex: 2 },
  { id: "unifesp_2024_022", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Mulher, 50 anos de idade, apresenta prurido em todo o corpo, fadiga, dor abdominal no quadrante superior direito, anorexia e alteração no padrão do sono. Exame físico: hepatoesplenomegalia, icterícia +/4, escoriações na pele por prurido, sem outras alterações. Qual é o diagnóstico mais provável?", options: ["Colangite biliar primária.", "Esquistossomose hepato esplênica.", "Esteato hepatite.", "Colecistite crônica calculosa."], correctIndex: 0 },
  { id: "unifesp_2024_023", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Homem, 24 anos de idade, apresenta dor abdominal diária e diarreia de 2 a 3 evacuações pastosas ao dia iniciadas há 1 ano, com perda de 7 kg no período. Exame físico: emagrecido, descorado ++/4+; presença de orifício em região anal com saída de secreção amarelada. Qual é o diagnóstico mais provável?", options: ["Retocolite ulcerativa.", "Câncer colorretal.", "Doença de Crohn.", "Tricuríase."], correctIndex: 2 },
  { id: "unifesp_2024_024", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Mulher, 30 anos de idade, fototipo III, auxiliar de escritório, apresenta lesões no dorso da mão direita há 5 dias, com ardor. Exame dermatológico: vesículas no antebraço direito com 1 mm de diâmetro em base eritematoedematosa que se estendem até o terço médio do braço e vesículas dispersas no V do decote. As lesões confluíam formando algumas bolhas na região distal do antebraço e intensificaram-se no dorso da mão direita próximo ao primeiro e segundo quirodáctilos. Qual é o diagnóstico mais provável?", options: ["Lúpus bolhoso.", "Dermatite atópica.", "Herpes Zoster.", "Eczema de contato fototóxico."], correctIndex: 3 },
  { id: "unifesp_2024_025", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher, 54 anos de idade, apresenta quadro de fenômeno de Raynaud e úlceras digitais há 1 ano. Pesquisa de autoanticorpos evidenciou FAN positivo 1/640 com padrão centromérico. Qual é o diagnóstico mais provável?", options: ["Lúpus eritematoso sistêmico.", "Dermatomiosite.", "Esclerose sistêmica.", "Vasculite de pequenos vasos."], correctIndex: 2 },
  { id: "unifesp_2024_026", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 65 anos de idade, agricultor, apresenta lesões nodulares, dolorosas, na sua mão direita, que surgiram duas semanas após ter se arranhado com um graveto enquanto trabalhava. Exame físico: presença de nódulos firmes e dolorosos à palpação no dorso da mão direita, com eritema ao redor e linfadenopatia axilar direita. Cultura do aspirado: bacilos gram-positivos, filamentosos, álcool ácido-resistentes. Qual é o agente etiológico mais provável?", options: ["Erysipelothrix rhusiopathiae.", "Nocardia brasiliensis.", "Mycobacterium tuberculosis.", "Raoultella terrígena."], correctIndex: 1 },
  { id: "unifesp_2024_027", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Mulher, 27 anos de idade, auxiliar de limpeza, com queixa de tosse seca intermitente há 3 anos. Tem rinossinusite alérgica e faz uso regular de beclometasona nasal. Nega dispneia e sibilos. Tem regurgitação e pirose. Nunca fumou. Exame físico sem alterações dignas de nota, exceto sobrepeso (IMC 28 kg/m2). Rx de tórax e espirometria normais. Considerando a hipótese diagnóstica mais provável, qual é a conduta mais adequada?", options: ["Teste molecular para Mycobacterium tuberculosis no escarro induzido.", "Tomografia de tórax de alta resolução.", "Nasofibroscopia.", "Teste terapêutico com inibidor de bomba de prótons e orientações dietético-posturais."], correctIndex: 3 },
  { id: "unifesp_2024_028", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Em 2022, a levedura Candida auris foi incluída pela Organização Mundial de Saúde como um dos patógenos fúngicos prioritários, demandando ações preventivas por parte de gestores de saúde de diferentes países. As características deste agente que justificam seu impacto na saúde humana é o seu alto potencial de:", options: ["Causar infecções do sistema nervoso central, levando a casos graves de meningoencefalites.", "Colonizar pacientes em ambiente hospitalar por tempo prolongado, de desenvolver resistência a antifúngicos e causar surtos em hospitais.", "Desenvolver quadros de infecção de sistema nervoso central em pacientes com doenças associadas a imunodepressão.", "Causar doenças crônicas de pele, altamente contagiosas pela presença de secreção e potencialmente resistentes a múltiplos antifúngicos."], correctIndex: 1 },
  { id: "unifesp_2024_029", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 50 anos de idade, apresenta-se para consulta de exame admissional, assintomático. Não tem doenças prévias e nem faz uso de medicações. Exame físico: PA = 145/95 mmHg, sem outras alterações. Em segunda consulta, apresentou medida de PA = 140/90 mmHg. Realizou Monitorização Ambulatorial de Pressão Arterial (MAPA) que mostra média pressórica de 24 horas de 125/75 mmHg e descenso noturno de 12%. Qual é o diagnóstico mais adequado?", options: ["Hipertensão do avental branco.", "Hipertensão mascarada.", "Hipertensão sustentada com efeito do avental branco.", "Hipertensão sustentada."], correctIndex: 0 },
  { id: "unifesp_2024_030", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Mulher, 54 anos de idade, apresenta queixa de dispneia aos moderados esforços há 3 meses. Nega doenças prévias e uso de medicações. Exame físico: PA = 100/70 mmHg, FC = 84 bpm; ausculta cardíaca com bulhas rítmicas com sopro sistólico 3+/6+ em foco mitral, irradiado para axila esquerda; ausculta pulmonar sem ruídos adventícios. Exames laboratoriais: creatinina = 1,0 mg/dL; K = 4,8 mEq/L. Ecocardiograma: evidenciou hipocinesia difusa, fração de ejeção de 38% e insuficiência mitral moderada. Qual é o tratamento mais adequado?", options: ["Bisoprolol, enalapril, dapagliflozina e espironolactona.", "Carvedilol, furosemida, amiodarona e dapagliflozina.", "Metoprolol, digoxina, hidroclorotiazida e enalapril.", "Atenolol, enalapril, furosemida e anlodipino."], correctIndex: 0 },
  { id: "unifesp_2024_031", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Você está na UBS atendendo um paciente que tem história de diabetes mellitus e hipertensão arterial. Nos exames atuais, ele apresenta creatinina = 1,8 mg/dl. Qual é a maneira recomendada para a avaliação da função renal deste paciente?", options: ["Estimar a taxa de filtração glomerular através da equação CKD-EPI.", "Estimar a taxa de filtração glomerular através da equação MDRD.", "Medir o clearance de creatinina na urina de 24 horas.", "Medir a filtração glomerular através da depuração de EDTA."], correctIndex: 0 },
  { id: "unifesp_2024_032", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Mulher, 30 anos de idade, refere vontade de parar de fumar. Fuma 20 cigarros por dia, sendo o primeiro 5 minutos após acordar, acha difícil não fumar em lugares proibidos e fuma mesmo quando está doente. O cigarro que traz mais satisfação é o primeiro da manhã e fuma mais frequentemente neste período. Nega etilismo e uso de outras drogas. Relata que já apresentou convulsão febril na infância. Para cessação do tabagismo, além da terapia cognitivo comportamental, qual é o tratamento mais indicado?", options: ["Iniciar bupropiona 150 mg/dia e adesivo de nicotina 21 mg/dia.", "Iniciar bupropiona 300 mg/dia e adesivo de nicotina 21 mg/dia.", "Iniciar adesivo de nicotina 21 mg/dia.", "Iniciar nortriptilina 25mg/dia, podendo chegar até a dose de 150 mg/dia, e adesivo de nicotina 21 mg/dia."], correctIndex: 3 },
  { id: "unifesp_2024_033", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Homem, 39 anos de idade, encontra-se no décimo dia após quimioterapia para tratamento de tumor cerebral. O hemograma mostra Hb = 8g/dl, leucócitos = 700/mm3, plaquetas = 49.000/mm3. Qual é o padrão de anemia mais provável neste caso?", options: ["Hipercrômica e macrocítica, hiperregenerativa com contagem de reticulócitos altos.", "Hipocrômica e microcítica, hiporregenerativa com contagem de reticulócitos baixos", "Normocrômica e normocítica, hiporregenerativa com contagem de reticulócitos baixos.", "Normocrômica e normocítica, hiperregenerativa com contagem de reticulócitos altos."], correctIndex: 2 },
  { id: "unifesp_2024_034", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Oftalmologia", text: "Homem, 55 anos de idade, previamente hígido, comparece para exame oftalmológico de rotina. Fundo de olho: lesão circunscrita, pigmentada e subrretiniana no olho esquerdo. Com este achado foi solicitado ultrassonografia ocular que evidenciou lesão com espessura de 5,5 mm e baixa refletividade interna. Baseado na principal hipótese diagnóstica, a investigação para estadiamento sistêmico deve ser iniciada por qual órgão?", options: ["Pulmão.", "Cérebro.", "Rim.", "Fígado."], correctIndex: 3 },
  { id: "unifesp_2024_035", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem, 42 anos de idade, tem história de litíase renal de repetição iniciada há 8 anos. O último evento faz 6 meses, com necessidade de ureterolitotripsia endoscópica. Não havia realizado estudo metabólico previamente. Exame físico: peso = 80 kg, altura = 1,72 m, PA = 122/78 mmHg. Exames: creatinina = 0,8 mg/dl, potássio = 4,8 mEq/l, cálcio total = 12,4 mg/dl, fósforo = 2,4 mg/dl; urina 1 = normal. Urina de 24 horas: sódio = 92 mEq, cálcio = 416 mg, citrato = 318 mg. Qual é a etiologia mais provável para a litíase de repetição neste caso?", options: ["Hipercalciúria idiopática.", "Hipocitratúria primária.", "Hiperparatireoidismo primário.", "Acidose tubular renal."], correctIndex: 2 },
  { id: "unifesp_2024_036", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 41 anos de idade, apresenta constipação intestinal há 3 semanas e fadiga há 2 semanas. Ela afirma que há 3 meses apresentou palpitações e diarreia por algumas semanas, com melhora espontânea. Antecedente pessoal: diabetes mellitus tipo 1 desde os 20 anos. Exame físico: afebril; FC = 48 bpm; PA = 124/88 mmHg; IMC = 22 kg/m2; tireoide indolor à palpação, com volume normal, sem outras alterações; pele fria e seca e cabelos ralos no couro cabeludo; edema não depressível +/4+ em ambas as extremidades inferiores. Considerando a hipótese diagnóstica mais provável, qual é a alteração de exame a ser encontrada?", options: ["Diminuição dos níveis do hormônio tiroestimulante.", "Captação difusa de iodo radioativo na cintilografia da tiroide.", "Anticorpos anti-tiroperoxidase positivos.", "Padrão homogêneo do parênquima na ultrassonografia da tiroide."], correctIndex: 2 },
  { id: "unifesp_2024_037", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 62 anos de idade, está em tratamento para diabetes mellitus tipo 2 com metformina e um inibidor de SGLT2. Os efeitos colaterais que podem ocorrer com uso destas medicações são, respectivamente:", options: ["redução dos níveis de vitamina B12 e cetoacidose euglicêmica.", "hipoglicemia e esteatose hepática.", "cetoacidose euglicêmica e insuficiência cardíaca.", "ganho de peso e hipertensão arterial."], correctIndex: 0 },
  { id: "unifesp_2024_038", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem, 64 anos de idade, é avaliado por diabetes mellitus tipo 2. Antecedentes pessoais: HAS, insuficiência cardíaca. Qual medicação é contraindicada neste caso?", options: ["Insulina NPH.", "Glicazida.", "Acarbose.", "Pioglitazona."], correctIndex: 3 },
  { id: "unifesp_2024_039", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Homem, 72 anos de idade, apresenta tosse produtiva, febre não aferida e sensação de cansaço há 5 dias. Exame físico: FR = 38 irpm, SpO2 = 82% e fala entrecortada. Após 30 minutos de ventilação mecânica não invasiva, a SpO2 = 87%, sem melhora do padrão respiratório, e opta-se por realizar intubação orotraqueal. Considerando o peso estimado do paciente de 70 kg, qual é o melhor ajuste inicial da ventilação mecânica?", options: ["Ventilação controlada a volume, volume corrente = 420 ml, PEEP = 5 cmH2O, FR = 30 irpm, relação I:E = 1:2, sensibilidade = 2 L/min, FiO2 = 100%.", "Ventilação controlada a volume, volume corrente = 630 ml, PEEP = 5 cmH2O, FR = 12 irpm, relação I:E = 1:2, sensibilidade = 2 L/min, FiO2 = 40%.", "Ventilação por pressão de suporte, pressão de suporte = 8 cm H2O, PEEP = 5 cm H2O, sensibilidade = 2 L/min, FiO2 = 100%.", "Ventilação por pressão de suporte, pressão de suporte = 12 cm H2O, PEEP = 5 cm H2O, relação I:E = 1:2, sensibilidade = 2 L/min, FiO2 = 40%."], correctIndex: 0 },
  { id: "unifesp_2024_040", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Homem, 52 anos de idade, apresenta dor e edema em joelho esquerdo há 3 dias. Nega traumas locais e relata episódios pregressos de monoartrite de dedo do pé, tornozelo e joelho de caráter intermitente com duração de 3 a 7 dias, nos últimos 5 anos. Tem hipertensão em uso de clortalidona 25 mg/dia. Exame físico: sinal da tecla positivo em joelho esquerdo. Tem hemograma normal, creatinina = 1,6 mg/dL (VR até 1,1 mg/dL), proteína C reativa = 10 mg/dL (VR até 1). Considerando o diagnóstico mais provável, qual é a conduta mais adequada?", options: ["Iniciar ceftriaxone e realizar lavagem articular", "Iniciar alopurinol.", "Iniciar anti-inflamatório não hormonal.", "Iniciar colchicina e substituir clortalidona por losartana."], correctIndex: 3 },
  { id: "unifesp_2024_041", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Oftalmologia", text: "Mulher, 34 anos de idade, queixa-se de dor à movimentação do olho esquerdo e escotoma na visão central do mesmo olho, há 5 dias. Portadora de hipertensão arterial sistêmica, nega vacinação ou infecção recentes. Exame: acuidade visual de 20/80 no olho esquerdo, discromatopsia e defeito pupilar aferente relativo, sem edema de papila. Qual é a conduta mais adequada?", options: ["Corticoterapia oral com prednisona; tomografia de crânio.", "Pulsoterapia com metilprednisolona; ressonância magnética de crânio.", "Tratamento conservador; orientação sobre melhora espontânea do quadro.", "Tratamento conservador; coleta VHS, PCR e biópsia de artéria temporal."], correctIndex: 1 },
  { id: "unifesp_2024_042", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 55 anos de idade, é admitida na UTI para pós-operatório de exérese de glioblastoma multiforme em região frontal direita. O procedimento não teve intercorrências, mas havia muito edema cerebral. O neurocirurgião solicita a manutenção da sedação até a manhã do dia seguinte, quando será realizada uma tomografia computadorizada de crânio. Qual é a melhor conduta para sedação e analgesia no momento?", options: ["Tiopental e fentanil.", "Midazolan e morfina.", "Tiopental e morfina.", "Propofol e fentanil."], correctIndex: 3 },
  { id: "unifesp_2024_043", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 65 anos de idade, deu entrada em sepses no PS referindo dor pélvica há 3 dias. Exame ginecológico: conteúdo vaginal purulento e fétido; colo amolecido, útero aumentado para 15 cm e doloroso à palpação. US pélvico: útero 260 ml, cavidade endometrial preenchida por conteúdo sólido-cístico com fluxo ao Doppler e interposição gasosa de permeio, sem plano de clivagem com o miométrio, eco endometrial irregular de 15 mm; ovários diminuídos de tamanho, hidrosalpinge bilateral de moderadas proporções. Qual é o diagnóstico mais provável?", options: ["Neoplasia maligna das tubas uterinas e endometrite.", "Abscesso tubo-ovariano e piometra.", "Mioma submucoso e endometrite.", "Neoplasia maligna do endométrio e piometra."], correctIndex: 3 },
  { id: "unifesp_2024_044", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 45 anos de idade, 2 partos vaginais, refere menstruações com duração de 20 dias, com saída de coágulos na maior parte dos dias. Refere cólica menstrual forte que necessita ser medicada com antiinflamatórios há 3 meses. Realizou uma ultrassonografia endovaginal: útero com volume 250 ml com 3 nódulos uterinos intramurais, o maior medindo 40 mm e 1 nódulo em colo uterino medindo 14 mm, espessura endometrial: 10 mm, ovários sem alterações. Qual é a conduta mais adequada?", options: ["Traquelectomia.", "Curetagem uterina.", "Miomectomias laparoscópica.", "Histerectomia vaginal."], correctIndex: 3 },
  { id: "unifesp_2024_045", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 33 anos de idade, casada há 5 anos, com infertilidade conjugal há 3 anos. O marido é saudável e tem 36 anos de idade. A paciente tem ciclos eumenorreicos e nega dismenorreia. Refere 1 abortamento aos 17 anos de idade. Baseado na imagem anexa (histerossalpingografia demonstrando sinéquias/obliteração da cavidade uterina), qual é a provável etiologia da infertilidade?", options: ["Fator uterino por sequela de aborto infectado.", "Fator uterino por mioma uterino submucoso.", "Fator tubário por endometriose peritoneal.", "Fator tubário por doença inflamatória pélvica."], correctIndex: 3 },
  { id: "unifesp_2024_046", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 56 anos de idade, refere perda urinária ao realizar exercícios físicos há 6 meses. II G II Partos normais. Nega comorbidades. Em estrogenioterapia vaginal. Ao exame físico observou-se os pontos Ba = -1, Bp = 0 e ponto C = -7. Qual é a conduta mais adequada?", options: ["Colpofixação retropúbica e perineoplastia.", "Fisioterapia do assoalho pélvico.", "Sling autólogo e correção da cistocele.", "Sling com tela de polipropileno e correção de enterocele."], correctIndex: 1 },
  { id: "unifesp_2024_047", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 42 anos de idade, assintomática e sem antecedentes familiares ou pessoais, sem alterações no exame mamário realizou mamografia de rastreamento, complemento mamográfico e estudo ultrassonográfico. Os principais achados estão apresentados na figura anexa (nódulo mamário sólido de contornos regulares). Qual é a conduta mais adequada?", options: ["Biópsia de nódulo com agulha grossa.", "Controle anual com mamografia.", "Controle de ultrassom em 6 meses.", "Solicitar ressonância magnética."], correctIndex: 1 },
  { id: "unifesp_2024_048", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Adolescente, 16 anos de idade, é levada ao serviço de saúde pela mãe, para avaliar resultado de preventivo de câncer de colo de útero mostrando lesão de baixo grau no citopatológico cérvico-vaginal. Segundo as diretrizes nacionais de rastreamento, a conduta mais adequada é:", options: ["Repetir a citologia em 6 meses.", "Repetir a citologia aos 25 anos de idade.", "Repetir a citologia em 3 anos.", "Encaminhar para colposcopia com biópsia."], correctIndex: 2 },
  { id: "unifesp_2024_049", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 33 anos de idade, nuligesta, refere que a última menstruação foi há 6 meses e não tem atividade sexual há 1 ano. Refere menarca aos 12 anos e que há 4 anos vem observando aumento do intervalo menstrual, variando de 50 a 90 dias até 6 meses atrás. Além disso refere aumento progressivo de peso, ondas de calor eventuais e diminuição de lubrificação vaginal. Nega aumento de pelos ou acne. IMC 21kg/m2. Exame mamário e ginecológico sem alterações. Considerando o diagnóstico mais provável, qual é a conduta mais adequada?", options: ["Contraceptivo hormonal combinado.", "Metformina e atividade física.", "Terapia de reposição hormonal.", "Inibidor de aromatase."], correctIndex: 2 },
  { id: "unifesp_2024_050", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Adolescente, 16 anos de idade, vai a UBS para orientação anticoncepcional. Refere ter tido 5 parceiros sexuais. Refere ciclos menstruais abundantes, com duração de 9 dias e cólica menstrual nos 4 primeiros dias. Última menstruação iniciou há 5 dias. Na Unidade encontram-se disponíveis os seguintes métodos: pílulas combinadas, implante subcutâneo, injetável mensal e DIU de cobre. Além da recomendação do uso de preservativos, qual é a orientação mais adequada?", options: ["Inserção imediata de DIU de cobre.", "Início da pílula combinada no próximo ciclo.", "Início do injetável mensal no próximo ciclo.", "Inserção imediata de implante subcutâneo."], correctIndex: 3 },
  { id: "unifesp_2024_051", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Mulher, 25 anos de idade, previamente saudável, politraumatizada, vítima de acidente de trânsito, é admitida na UTI após drenagem de contusão cerebral frontal direita e drenagem de tórax à direita devido a um pneumotórax hipertensivo. O quadro hemodinâmico é estável e há perspectiva de mantê-la sedada e em ventilação mecânica nas próximas 48 a 72 horas. Qual é a conduta mais adequada em relação à terapia nutricional?", options: ["Iniciar uma oferta energética de 15 a 20 kcal/kg/dia, por via enteral.", "Iniciar nutrição parenteral exclusiva o mais precocemente possível.", "Usar fórmula enteral com ômega 3, óleos de borragem e antioxidantes.", "Manter soro de manutenção por 48 a 72 horas e depois iniciar nutrição oral."], correctIndex: 0 },
  { id: "unifesp_2024_052", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Tercigesta de 24 semanas, hígida, com 2 partos anteriores no termo, o último há 1 ano e 3 meses, vem a consulta pré-natal. Afirma ter recebido a vacina tríplice acelular do adulto (dtpa) nas gestações anteriores. Qual é a orientação mais adequada em relação a imunização com a referida vacina na gravidez atual?", options: ["Receber a vacina após a 32ª semana.", "Receber a vacina neste momento.", "Não receber a vacina, uma vez que a paciente já está imune.", "Não receber a vacina, pois a paciente não pertence a grupo de risco."], correctIndex: 1 },
  { id: "unifesp_2024_053", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Secundigesta de 37 semanas, 40 anos de idade, parto cesáreo há 8 anos, vem encaminhada ao pronto atendimento por pressão arterial de 140 x 95 mmHg, assintomática. Níveis pressóricos sempre normais durante a gestação atual. Exame físico: AU: 34 cm; BCF: 148 bpm; DU ausente. Toque vaginal: colo grosso, posterior, pérvio para 2,0 cm, cefálico. Extremidades: edema +/4+ membros inferiores. Exames laboratoriais: Hb = 11,6 g/dL, Htc = 33,7 %; leucograma = 11700 glóbulos brancos; plaquetas = 224.000/mm3; TGO/TGP = 14/12 U/L; creatinina = 0,6 mg/dL. Urina I = prot +. Qual é a conduta mais indicada?", options: ["Parto cesáreo imediato.", "Indução imediata do parto.", "Internação para observação clínica e repetição dos exames laboratoriais.", "Prescrição de hipotensores e seguimento ambulatorial."], correctIndex: 1 },
  { id: "unifesp_2024_054", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 66 anos de idade, hipertensa, em acompanhamento com a geriatria, refere 2 episódios de sangramento vaginal de pequena intensidade há 1 mês. Menopausa aos 50 anos de idade, não faz terapia hormonal. Exame físico sem alterações. Ultrassom pélvico revelou eco endometrial de 3 mm. A conduta mais adequada é:", options: ["Estrogenioterapia transdérmica.", "Estrogenioterapia vaginal.", "Ablação endometrial.", "Observação clínica."], correctIndex: 3 },
  { id: "unifesp_2024_055", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Puérpera, com parto vaginal a termo de recém-nascido de 4200g, apresentou sangramento vaginal intenso logo após a expulsão da placenta. A monitorização revelou, naquele momento, pulso de 110 bpm e pressão arterial de 85 x 55mmHg. Oito minutos após a infusão endovenosa de ocitocina e administração intramuscular de ergometrina, houve redução significativa do sangramento. Peso das compressas ao final do procedimento de 700g. A enfermeira acionou corretamente o código de hemorragia pós-parto, pois:", options: ["As compressas pesaram mais de 500g.", "Houve instabilidade hemodinâmica.", "Foram necessários mais de um agente uterotônico.", "O sangramento foi controlado após o quinto minuto."], correctIndex: 1 },
  { id: "unifesp_2024_056", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Puérpera no 2° dia pós-parto vaginal, apresenta dificuldade de deambular por intensa tontura associada a palpitação e falta de ar. No prontuário, há relato de retenção placentária, com necessidade de extração manual da placenta. Exame físico geral: REG, descorada 3+/4+, hidratada, taquipneica, pulso de 120 bpm, PA 95x70 mmHg. Abdome: útero contraído 2cm abaixo da cicatriz umbilical, indolor. OGE: presença de edema importante dos grandes lábios, sutura perineal de bom aspecto. Loquiação fisiológica. Extremidades: edema 2+/4+ membros inferiores. Qual é o diagnóstico mais provável?", options: ["Tromboembolismo pulmonar.", "Endometrite puerperal.", "Restos placentários.", "Anemia pós-parto."], correctIndex: 3 },
  { id: "unifesp_2024_057", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Secundigesta, 36 semanas de gestação, foi internada às 18 horas em trabalho de parto prematuro com 5cm de dilatação cervical. Refere ter feito uso de enoxaparina sódica na dose de 40mg/dia, durante toda a gestação, por ser portadora de trombofilia hereditária. Última aplicação ocorreu as 8 horas da manhã do mesmo dia. Durante o período expulsivo do parto, às 22 horas, há indicação de cesárea por desacelerações tardias recorrentes. Qual é a técnica anestésica mais indicada?", options: ["Peridural.", "Anestesia geral.", "Duplo bloqueio (raquianestesia + peridural).", "Raquianestesia."], correctIndex: 3 },
  { id: "unifesp_2024_058", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "De acordo com a recém-publicada Diretriz Nacional de assistência ao parto normal do ministério da saúde, qual das alternativas é correta quanto ao manejo do primeiro período do parto em parturientes saudáveis e de risco habitual?", options: ["O uso de ocitocina é recomendado para prevenção de atraso no trabalho de parto em mulheres recebendo analgesia peridural.", "O exame pélvico digital deve ser realizado a cada 2 horas para avaliação da progressão do trabalho de parto.", "Cardiotocografia deve ser oferecida de rotina na admissão para avaliação do bem-estar fetal.", "Amniotomia está indicada diante da falha de progressão do primeiro período do parto."], correctIndex: 3 },
  { id: "unifesp_2024_059", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Ao realizar toque vaginal em parturiente no período expulsivo, obstetra notou a presença de bossa e de cavalgamento dos ossos do crânio. Estes achados são mais frequentemente encontrados em qual situação?", options: ["Desproporção cefalopélvica.", "Cefálica defletida de 2º grau.", "Cranioestenose.", "Assinclitismo posterior."], correctIndex: 0 },
  { id: "unifesp_2024_060", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Secundigesta, 28 anos de idade, parto anterior no termo. Primeira consulta em UBS com diagnóstico de gravidez tópica de 8 semanas. Realizado teste rápido para sífilis, com resultado positivo. No cartão pré-natal da gestação anterior encontra-se anotado o diagnóstico de sífilis e tratamento feito com Penicilina Benzatina, 7.200.000 UI. Feito seguimento sorológico, há 6 meses, com VDRL de 1:2. Qual é a conduta mais indicada?", options: ["Solicitar VDRL.", "Tratar com penicilina benzatina 2.4000.000 UI.", "Tratar com penicilina benzatina 7.200.000 UI.", "Solicitar FTA-Abs."], correctIndex: 0 },
  { id: "unifesp_2024_061", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Gestante de 34 semanas apresenta sorologia (colhida há 2 semanas) positiva para Citomegalovírus, com IgM e IgG positivos. Refere quadro gripal há cerca de 1 mês, com febre baixa, mialgia e cefaleia. A sorologia no início do prénatal, realizada no 2° trimestre, apresentava IgG positivo e IgM negativo. Qual é a conduta mais adequada?", options: ["Amniocentese para pesquisa do DNA viral.", "Observação clínica.", "Prescrição de valaciclovir.", "Ressonância magnética."], correctIndex: 1 },
  { id: "unifesp_2024_062", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 50 anos de idade, apresenta fraqueza e espasmo muscular progressivo nos membros inferiores. Exame neurológico com hiperreflexia e eletroneuromiografia sugere acometimento de segundo neurônio motor. Qual é o diagnóstico mais provável?", options: ["Síndrome de Guillain-Barré.", "Esclerose múltipla.", "Esclerose lateral amiotrófica (ELA).", "Doença de Parkinson."], correctIndex: 2 },
  { id: "unifesp_2024_063", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher, 25 anos de idade, apresenta fraqueza muscular ao subir escadas e ao fim do dia, há dois meses. Percebeu visão dupla quando trabalha em frente ao computador por longos períodos. Considerando o diagnóstico mais provável quais exames complementares devem ser solicitados?", options: ["Ressonância magnética de crânio e pesquisa do anticorpo anti-glicoproteina.", "Tomografia de tórax e pesquisa de anticorpo anti-receptor de acetilcolina.", "Ressonância de pelve e pesquisa do anticorpo anti-NMDAR.", "Biópsia muscular e pesquisa do anticorpo anti-MUSK."], correctIndex: 1 },
  { id: "unifesp_2024_064", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Celebridade nacional, 52 anos de idade, foi submetido a um transplante de coração em um hospital privado uma semana após a indicação formal. Este tempo é inferior à média de espera para este tipo de transplante. O paciente foi priorizado em função da gravidade do quadro clínico de acordo com a legislação vigente, além da disponibilidade de um órgão compatível em cidade próxima. Qual o princípio do SUS se relaciona mais especificamente com esta priorização?", options: ["Humanização.", "Equidade.", "Regionalização.", "Integralidade."], correctIndex: 1 },
  { id: "unifesp_2024_065", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher, 82 anos de idade, tem diagnóstico de diabetes, hipertensão arterial, hipotiroidismo e artrose de joelhos. Filha refere lapsos de memória eventuais. Faz uso de levotiroxina (75 mcg/dia), losartana (100 mg/dia), hidroclorotiazida (25 mg/dia), gliclazida (60 mg/dia) e insulina NPH (20 UI pela manhã e 16 UI ao deitar). Ganhou 2 kg desde a última consulta. Trouxe controles de PA nos limites da normalidade. Exames laboratoriais: TSH = 5,4 μUI/mL, glicemia de jejum = 84 mg/dL e HbA1c = 5,9%. Qual é a conduta mais apropriada e sua justificativa?", options: ["Manter conduta, pois os exames revelam controle terapêutico adequado.", "Aumentar a dose da levotiroxina por TSH aumentado e ganho de peso.", "Aumentar a dose da levotiroxina para reavaliar declínio cognitivo.", "Diminuir medicações de diabetes por risco de hipoglicemia."], correctIndex: 3 },
  { id: "unifesp_2024_066", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "De acordo com o artigo 128, inciso II do Código Penal, o abortamento é um procedimento lícito \"quando a gravidez resulta de estupro\", que é um crime tipificado no artigo 213 do Código Penal. Nessa situação, para que se faça a interrupção da gestação, a vítima deve apresentar:", options: ["O Termo de Consentimento Livre e Esclarecido e o Termo de Responsabilidade.", "O Termo de Consentimento Livre e Esclarecido e o Boletim de Ocorrência.", "O Boletim de Ocorrência, a Autorização Judicial e o termo de Responsabilidade.", "O Laudo do Instituto Médico Legal, o Boletim de Ocorrência e a Autorização Judicial."], correctIndex: 0 },
  { id: "unifesp_2024_067", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Homem, 62 anos de idade, refere certo desânimo envolvendo aspectos físicos e mentais, perda de memória e formigamento simétrico em extremidades. Faz uso de losartana, metformina, insulina NPH, sinvastatina e omeprazol. Qual é a hipótese diagnóstica mais provável?", options: ["Hipotiroidismo.", "Deficiência de vitamina B12.", "Episódios de hipoglicemia.", "Depressão."], correctIndex: 1 },
  { id: "unifesp_2024_068", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Sobre a Política Nacional de Saúde do Trabalhador, é correto afirmar que:", options: ["Tem como objetivo fortalecer a Vigilância em Saúde do Trabalhador (VISAT), de modo que esta desenvolva ações independentes e unilaterais, prescindindo da integração com os demais componentes da Vigilância em epidemiológica.", "Contempla as ações propostas para trabalhadores em situação de vulnerabilidade socioeconómicas, inseridos em atividades informais de trabalho.", "Se trata de um conjunto de políticas de saúde no âmbito do SUS, considerando a transversalidade das ações de saúde do trabalhador e a ação de se trabalhar, como um dos determinantes do processo saúde-doença.", "Considera a necessidade da constituição de uma rede de serviços paralelas ao SUS, devido as demandas de atendimento dos trabalhadores em processo de adoecimento."], correctIndex: 1 },
  { id: "unifesp_2024_069", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Considere os três estudos fictícios abaixo (I, II e III): I. Um estudo transversal, incluindo pessoas com o mesmo risco cardiovascular, mostrou que o consumo de alimentos ricos em betacaroteno estava associado de forma inversa (RP=0,74; IC95%: 0,62-0,89) com a ocorrência de evento cardiovascular. II. Em estudo de coorte, que acompanhou 20 mil pessoas com o mesmo risco cardiovascular por 15 anos, o consumo de alimentos ricos em betacaroteno teve associação inversa (RR=0,85; IC95%: 0,77-0,97) com a incidência de evento cardiovascular. III. Com as evidências dos estudos observacionais acima citados, foi realizado um ensaio clínico incluindo pessoas com o mesmo risco cardiovascular, que após randomização, recebiam extrato de betacaroteno ou placebo. Foi evidenciado maior incidência de eventos cardiovasculares no grupo que recebeu a intervenção com betacaroteno (RR=1,58; IC95%: 1,10-3,45) comparado ao grupo placebo. Com relação à recomendação de uso de betacaroteno como medida preventiva para evento cardiovascular, qual é a alternativa correta?", options: ["O estudo III, de maior validade interna, define a não recomendação do uso de betacaroteno na prática clínica.", "Considerando os benefícios apresentados em 2 dos estudos, o uso de betacaroteno é recomendado.", "Nenhum dos estudos apresentou estimativas estatisticamente significativas, o que indica que a hipótese nula deve ser considerada em todos os 3 estudos.", "Os estudos I, II e III em conjunto não permitem uma recomendação sobre o uso do betacaroteno na prática clínica."], correctIndex: 0 },
  { id: "unifesp_2024_070", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Uma nova terapia com eficácia de 70% na redução da mortalidade foi introduzida para o tratamento de uma doença crônica, sem cura, com prevalência estimada de 10% na população. Assinale a alternativa correta em relação ao primeiro impacto esperado com a introdução da nova terapia.", options: ["A prevalência da doença deve diminuir.", "A prevalência da doença deve aumentar.", "A incidência da doença deve aumentar.", "A incidência da doença deve diminuir."], correctIndex: 1 },
  { id: "unifesp_2024_071", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um rastreamento populacional pode parecer muito eficaz para um determinado tipo de câncer, mas tal achado pode ser apenas produto de tendenciosidade que afeta a validade das conclusões. Sabendo disso, qual é a alternativa correta?", options: ["A medida da taxa de mortalidade estrato-etária específica pelo câncer costuma ser uma maneira enviesada de avaliar a efetividade do rastreamento.", "Comparar a sobrevida após o diagnóstico em rastreados e em não-rastreados costuma ser a melhor maneira de indicar a utilidade de um rastreamento em Saúde Pública.", "Os cânceres detectados em rastreamentos podem ser de crescimento mais lento que os cânceres detectados por meio de sinais e sintomas clínicos.", "A maior taxa de incidência de um tipo de câncer de população rastreada comparada a de não rastreadade prova a validade e eficácia de um teste de rastreamanto."], correctIndex: 2 },
  { id: "unifesp_2024_072", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Para verificar a correlação entre a Taxa de Mortalidade Infantil (TMI) e o percentual de unidades de saúde que obtiveram bom desempenho na avaliação do Programa Nacional de Melhoria do Acesso e da Qualidade da Atenção Básica (%PMAQ) nos estados brasileiros, foi calculado o coeficiente de correlação de Pearson, resultando em um valor de -0,534 (P-valor = 0,005). Com base nessas informações, qual é a afirmativa correta?", options: ["Estados com TMI mais altas tendem a %PMAQ menores, ao nível de confiança de 5%.", "Estados com TMI mais altas tendem a %PMAQ menores, ao nível de significância de 5%.", "Não há correlação entre TMI e %PMAQ, ao nível de confiança de 5%.", "Não há correlação entre TMI e %PMAQ, ao nível de significância de 5%."], correctIndex: 1 },
  { id: "unifesp_2024_073", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "No dia 5 de setembro de 2021, o jogo entre Brasil e Argentina foi interrompido para fiscalizar jogadores argentinos que haviam violado regras relacionadas à Covid-19, no Brasil. Qual é a área da Vigilância em Saúde brasileira com poder de polícia que atuou naquele momento?", options: ["Epidemiológica.", "Saúde do Trabalhador.", "Ambiental.", "Sanitária."], correctIndex: 3 },
  { id: "unifesp_2024_074", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Uma revisão sistemática investigou a associação entre consumo diário de mais de duas porções de bebida adoçada e mortalidade, evidenciando o risco relativo e o seu respectivo intervalo de confiança de 95% de 1,31 e 1,15-1,50. Com base neste resultado, qual é a alternativa correta?", options: ["O risco de morte entre aqueles que consumiram mais de duas porções de bebidas adoçadas foi 31% maior em relação ao grupo de referência.", "O risco de morte aumentou conforme aumentou o consumo diário de bebida adoçada, variando de 15% a 50%.", "O risco de morte aumentou em 50% entre aqueles que consumiram mais de duas porções diárias da bebida.", "O risco de morte não foi associado ao consumo de bebida adoçada."], correctIndex: 0 },
  { id: "unifesp_2024_075", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um determinado município, no ano de 2021, a população estimada era de 100.000 homens e 100.000 mulheres. Nesse ano ocorreram 1000 óbitos entre os homens (310 por doenças do aparelho circulatório, DAC) e 700 óbitos entre mulheres (260 por DAC). A partir desses dados, qual é a alternativa correta?", options: ["As mulheres têm maior risco de morrer por DAC, pois o coeficiente de mortalidade proporcional é maior entre elas.", "Os homens têm menor risco de morrer por DAC, pois o coeficiente de mortalidade proporcional é menor entre eles.", "As mulheres têm menor risco de morrer por DAC, pois o coeficiente de mortalidade específico é maior entre elas.", "Os homens têm maior risco de morrer por DAC, pois o coeficiente de mortalidade específico é maior entre eles."], correctIndex: 3 },
  { id: "unifesp_2024_076", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um teste de rastreamento para câncer tem 90% de sensibilidade e 80% de especificidade. Aplicado em uma população cuja prevalência da doença é de 10%, qual é a probabilidade de um teste positivo representar um indivíduo realmente doente?", options: ["99%", "67%", "10%", "33%"], correctIndex: 3 },
  { id: "unifesp_2024_077", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um gestor em saúde quer saber o nível de satisfação dos clientes com os serviços médicos prestados. Ele sabe que precisa entrevistar pelo menos 250 clientes para estimar, com uma margem de erro de 3%, a proporção daqueles insatisfeitos com o serviço. Qual dos seguintes planos de amostragem permite generalizar os resultados da pesquisa para todos os clientes?", options: ["Fazer um evento de promoção de saúde e convidar todos os clientes, selecionando aleatoriamente 250 clientes que comparecerem no evento.", "Enviar um questionário por aplicativo de mensagem para todos os clientes e levar em consideração os primeiros 250 que responderem.", "Enviar um questionário por e-mail para 250 clientes selecionados aleatoriamente e acompanhar aqueles que não responderem.", "Pesquisar os primeiros 250 clientes que comparecerem no estabelecimento em um dia aleatório."], correctIndex: 2 },
  { id: "unifesp_2024_078", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação à notificação compulsória de doenças, agravos e eventos assinale a alternativa correta.", options: ["A imputação dos dados provenientes das notificações é realizada no Sistema de Informação de Agravos de Notificação.", "Baseia-se em uma lista nacional unificada, sendo vedado a Estados e Municípios a inclusão de itens sem que haja uma pactuação tripartite.", "É um ato médico mas que pode ser exercida por outros profissionais de saúde, desde que sigam as diretrizes do Sistema Único de Saúde.", "Sua obrigatoriedade aplica-se a cidadãos brasileiros, sendo facultativa no caso de pacientes estrangeiros."], correctIndex: 0 },
  { id: "unifesp_2024_079", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Homem, 70 anos de idade, tem história prévia de infarto agudo do miocárdio e foi hospitalizado em uma UTI com monitoramento contínuo da pressão arterial. Os valores a seguir representam medidas consecutivas da pressão arterial sistólica (PAS) deste paciente: 75, 110, 80, 110, 90 e 75 mmHg. Qual dos seguintes valores representa a mediana da PAS deste paciente?", options: ["80 mmHg.", "95 mmHg.", "85 mmHg.", "110 mmHg."], correctIndex: 2 },
  { id: "unifesp_2024_080", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Mulher, 21 anos de idade, casada, sem filhos, procura a UBS em busca de método contraceptivo. Depois de ser informada de todos os métodos possíveis, ela opta pela laqueadura tubária. Segundo a Lei nº 14.443 de 02 de setembro 2022, que altera a Lei nº 9.263 de 12 de janeiro de 1996 sobre o planejamento familiar, qual é a alternativa correta?", options: ["O procedimento pode ser realizado, mas somente com a autorização do cônjuge.", "O procedimento só poderia ser realizado se a paciente tivesse ao menos um filho vivo.", "O procedimento só poderia ser realizado se a paciente tivesse ao menos dois filhos vivos.", "O procedimento pode ser realizado, sem a necessidade da autorização do cônjuge."], correctIndex: 3 },
  { id: "unifesp_2024_081", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 68 anos de idade, apresenta piora de tremor antigo que atualmente tem impactado na vida social, ao deixar de frequentar a padaria para tomar café, por comentários jocosos como se estivesse de ressaca. Observou que os sintomas melhoram quando ingere álcool. Qual é o diagnóstico mais provável e a investigação e conduta mais adequadas?", options: ["Tremor fisiológico; não é necessária investigação; evitar gatilhos.", "Tremor essencial exacerbado; não é necessária investigação; propranolol.", "Tremor parkisoniano; eletroneuromiografia; levodopa.", "Esclerose múltipla; ressonância magnética de crânio; terapêutica de acordo com resultado."], correctIndex: 1 },
  { id: "unifesp_2024_082", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Homem, 30 anos de idade, apresenta erupção cutânea dolorosa e pruriginosa que piorou desde que ele a notou pela primeira vez, 1 dia atrás. Exame físico: erupção macular eritematosa com várias vesículas que não cruzam a linha média sobre a região frontal esquerda e área periorbital. A terapia com aciclovir é iniciada. Qual dos seguintes passos é o mais apropriado?", options: ["Solicitar sorologia para HIV.", "Associar corticoide oral.", "Realizar biópsia de pele.", "Solicitar teste de Tzanck."], correctIndex: 0 },
  { id: "unifesp_2024_083", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido (RN) a termo no primeiro dia de vida, filho de mãe com sífilis que iniciou o tratamento com penicilina benzatina há duas semanas. Exame físico: sem alterações. VDRL da mãe e do RN no momento do parto com titulação de ¼. Exames do RN: Rx de ossos longos normal, hemograma normal e impossibilidade de coleta de líquor. Considerando que esse RN poderá ser acompanhado de forma adequada, qual tratamento deve ser instituído?", options: ["Penicilina cristalina por 10 dias.", "Penicilina procaína por 10 dias.", "Penicilina benzatina em dose única.", "Não há necessidade de medicar."], correctIndex: 0 },
  { id: "unifesp_2024_084", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Rotavírus é o patógeno que mais frequentemente causa gastroenterite aguda em lactentes, constituindo importante causa de internações hospitalares. A vacinação é importante estratégia para redução da sua morbidade, mas é contraindicada em qual das seguinte situações?", options: ["História familiar de intussuscepção intestinal.", "Imunodeficiência combinada grave.", "Prematuridade extrema.", "Contactante domiciliar no primeiro trimestre de gestação."], correctIndex: 1 },
  { id: "unifesp_2024_085", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 2 anos de idade, é levado ao PS pela mãe devido a acidente doméstico com água fervente. No exame físico, qual dos achados sugere que se trata de abuso físico?", options: ["Profundidade não uniforme.", "Bordas definidas.", "Lesão em face.", "Marcas de respingos."], correctIndex: 1 },
  { id: "unifesp_2024_086", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 10 anos de idade, apresenta dificuldade escolar, diabetes diagnosticado há 2 anos, em uso de insulina, e intolerância ao exercício notada nas aulas de educação física: consegue correr por 10 minutos, quando apresenta dor em queimação nas coxas e panturrilhas. Que exame laboratorial é o marcador para a principal hipótese diagnóstica?", options: ["Perfil lipídico.", "Amônia sérica.", "CPK.", "Lactato sérico."], correctIndex: 3 },
  { id: "unifesp_2024_087", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 3 anos de idade, é levado ao PS apresentando tosse e febre há 5 dias com piora do estado geral e da febre e relato de canseira no peito há 3 dias. Exame físico após normalização da temperatura: MEG, hidratado e acianótico. FR = 48 ipm, FC = 130 bpm e SpO2 = 90%. Tiragem intercostal e subdiafragmática moderadas e estertores crepitantes em base direita. De acordo com o diagnóstico mais provável quais as características esperadas na imagem radiológica?", options: ["Opacidade densa, homogênea e localizada.", "Opacidade que permite visualização dos vasos.", "Densidades lineares e irregulares.", "Padrão peribrônquico."], correctIndex: 0 },
  { id: "unifesp_2024_088", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 2 meses de idade, assintomático, nascido pequeno para a idade gestacional, sem intercorrências na gestação, Apgar 09/10 e está em aleitamento artificial desde o nascimento. Teve resultado positivo para fenilcetonúria na triagem neonatal em amostra coletada com 24 horas de vida, que não se confirmou em outras duas amostras coletadas posteriormente. Qual é o fator que justifica a discordância entre os resultados?", options: ["Idade da coleta das amostras.", "Aleitamento artificial.", "Hiperfenilalaninemia materna.", "Restrição de crescimento intrauterino."], correctIndex: 2 },
  { id: "unifesp_2024_089", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 18 meses de idade, com anemia desde os 9 meses, que não melhorou com o tratamento com sulfato ferroso. Nasceu a termo, com 3250 g, sem intercorrências. Recebeu aleitamento materno exclusivo até o 6º mês, atualmente ingere carne 2 vezes na semana e aceita verduras cozidas. Não tem antecedentes de anemia na família. Exame físico: peso e estatura entre os percentis 5 e 10; descorado ++/4+; fígado e baço não palpáveis. Exames laboratoriais: Hemograma: eritrócitos = 5,2 milhões/mm3; Hb = 9,8 g/dL; VCM = 69; HCM = 21; RDW = 13,8%; reticulócitos = 1,5%; GB = 9200 (distribuição normal); plaquetas = 325.000/mm3; Ferro sérico = 50 mcg/dL; Ferritina = 34 mcg/dL; Saturação de transferrina = 28%. Qual é o diagnóstico mais provável?", options: ["Anemia Ferropriva.", "Aplasia pura da série vermelha.", "Talassemia minor.", "Deficiência de G6PD."], correctIndex: 2 },
  { id: "unifesp_2024_090", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 9 anos de idade, apresentou há 1 ano quadro de febre, poliartrite aguda migratória e cardite, com velocidade de hemossedimentação (VHS) de 65 mm (valor referência < 15 mm), além de evidência de infecção pelo estreptococo do grupo A por elevação de antiestreptolisina O (ASLO). Para evitar novos surtos da doença é utilizada a profilaxia secundária com penicilina benzatina. O tempo de realização da profilaxia secundária será definido por qual dos fatores abaixo?", options: ["Comprometimento cardíaco.", "Comprometimento articular.", "Nível sérico de ASLO.", "Valor de VHS."], correctIndex: 0 },
  { id: "unifesp_2024_091", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "RN masculino, nasceu de parto cesárea iterativa, com 35 semanas de idade gestacional, líquido amniótico meconial 1+/4+, Apgar 08 e 09 nos primeiro e quinto minutos. Com 48 horas de vida, apresentava FR = 70 irpm, boletim de Silverman-Andersen = 4, sem outras alterações ao exame físico. Considerando o diagnóstico mais provável, qual é o mecanismo fisiopatológico primário envolvido?", options: ["Atraso na reabsorção do líquido intersticial pulmonar.", "Deficiência de surfactante.", "Aspiração e obstrução de pequenas vias aéreas.", "Persistência da circulação fetal."], correctIndex: 0 },
  { id: "unifesp_2024_092", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 10 dias de vida, nascido a termo sem intercorrências no pré-natal ou ao nascimento. A mãe traz na primeira consulta de puericultura o resultado da triagem neonatal coletada no terceiro dia de vida. A única alteração nos testes é a dosagem de galactose total 12 mg/dL (Valor de referência <= 9mg/dl). Exame físico: bom estado geral, ganho de peso adequado para a idade e sem alterações. Qual é a conduta mais adequada?", options: ["Retirar o leite materno e repetir a dosagem de galactose total em sangue seco em papel filtro.", "Retirar leite de vaca e derivados da dieta materna e manter o aleitamento materno.", "Repetir a dosagem de galactose total em sangue seco em papel filtro.", "Não há a necessidade de coleta de nenhum exame."], correctIndex: 0 },
  { id: "unifesp_2024_093", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 1 ano e 4 meses de idade, é acompanhada na UBS desde o nascimento. Sua mãe tem 28 anos, G1 P1 A0. Antecedentes: nasceu de parto normal, com 35 semanas e 2 dias e peso de 2400 g, sem intercorrências; alta com a mãe no 3º dia de vida. Nega internações prévias. Apresentou resfriados após iniciar frequência à creche aos 9 meses, sem complicações. A mãe está preocupada pois acha que a criança fala poucas palavras, comparando com sua sobrinha da mesma idade. A criança fala cerca de 20 palavras e se comunica apontando para objetos; entende alguns comandos; usa a colher, tira sapato com ajuda, não engatinhou e anda sem apoio há 1 mês. Assiste desenhos no celular quase todos os dias, por cerca de uma hora ou mais. Qual é a avaliação do desenvolvimento da criança e quais são as orientações para sua mãe?", options: ["Desenvolvimento normal; estimular atividades e o contato com a natureza, ler histórias e cantar com a criança e excluir celular.", "Desenvolvimento normal; proporcionar atividades com outras crianças e reduzir tempo de tela para meia hora/dia.", "Desenvolvimento motor e de linguagem atrasados; levar a criança a parques para brincar e solicitar exame audiológico.", "Desenvolvimento de linguagem atrasado; encaminhar para fonoaudiologia, ler histórias e excluir celular."], correctIndex: 0 },
  { id: "unifesp_2024_094", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido de mãe diagnosticada com tuberculose pulmonar e tratamento iniciado 10 dias antes do parto. Qual é a conduta terapêutica para a criança?", options: ["Vacinar com BCG e tratar com isoniazida por 3 meses, sem necessidade de realizar o PPD antes ou depois do uso da profilaxia com isoniazida, se criança assintomática", "Não dar vacina BCG, realizar PPD na primeira semana e se PPD não reator, vacinar com BCG, sem necessidade de profilaxia.", "Não dar vacina BCG, iniciar profilaxia com isoniazida por 3 meses, realizar PPD e se PPD > 5 mm, com criança assintomática, manter isoniazida até 6 meses.", "Vacinar com BCG e fazer acompanhamento mensal até o 6º mês de vida, realizar PPD se apresentar alguma sintomatologia"], correctIndex: 2 },
  { id: "unifesp_2024_095", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 1 ano e 6 meses de idade, há 2 dias iniciou quadro de vômitos e febre baixa (que cessaram) e evoluiu com diarreia, caracterizada por fezes líquidas, sem sangue e sem muco, com frequência de cerca de 4 vezes ao dia. Exame físico: bem nutrido, em bom estado geral e sem sinais de desidratação. Além de orientar o uso de soro oral após cada evacuação e os sinais de perigo para retorno ao serviço de saúde, qual conduta é recomenda pelo Ministério da Saúde?", options: ["Oferecer dieta hipogordurosa e prescrever probiótico.", "Manter a alimentação habitual e prescrever zinco oral.", "Manter a alimentação habitual e prescrever probiótico.", "Retirar lactose da dieta e prescrever zinco oral."], correctIndex: 1 },
  { id: "unifesp_2024_096", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 3 anos de idade, apresenta o segundo episódio de infecção do trato urinário, sendo indicada investigação de cicatriz renal. Com este propósito, qual é o exame indicado?", options: ["Cintilografia renal com DMSA.", "Ultrassonografia de rins e vias urinárias.", "Cintilografia renal com diurético.", "Uretrocistografia miccional."], correctIndex: 0 },
  { id: "unifesp_2024_097", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, 10 dias de vida, mãe primigesta, parto normal a termo, sem intercorrências na gestação ou no parto. Mãe com sorologias para toxoplasmose realizadas no início de cada trimestre gestacional com IgM e IgG não reagentes. Criança apresentou teste do pezinho positivo para toxoplasmose. Como conduzir este caso?", options: ["Repetir sorologia para toxoplasmose da mãe e do RN; se ambas positivas, tratar o RN com sulfadiazina, pirimetamina e ácido folínico por 1 ano.", "Considerar o teste do pezinho falso positivo, pois as sorologias materna durante a gestação foram negativas; não tratar a criança.", "Tratar o RN com sulfadiazina, pirimetamina e ácido folínico por 42 dias, sem necessidade de repetir sorologias.", "Repetir o teste do pezinho e, se positivo para toxoplasmose, tratar o RN com espiramicina por 1 ano."], correctIndex: 0 },
  { id: "unifesp_2024_098", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 13 anos de idade, nascido com peso e comprimento adequados, sem doença crônica ou uso de medicação, foi encaminhado ao ambulatório por déficit de crescimento. Na avaliação apresenta estatura entre -1,0 e -2,0 DP e estatura alvo entre -1,0 e 0,0 DP. A idade óssea é de 11 anos e o desenvolvimento puberal avaliado pelos critérios de Tanner, P1 G1. Seu crescimento foi de 4,5 cm no último ano. Qual é o diagnóstico e a conduta mais adequada?", options: ["Atraso constitucional, hormônio do crescimento.", "Baixa estatura familiar, seguimento clínico.", "Atraso constitucional, seguimento clínico.", "Baixa estatura idiopática, hormônio do crescimento."], correctIndex: 2 },
  { id: "unifesp_2024_099", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente, 4 meses de idade, com pneumonia bacteriana, apresenta FR = 70 irpm, retração intercostal e subdiafragmática, batimento de asa de nariz, e gemido expiratório. Qual dos achados clínicos representa um mecanismo compensatório para melhorar a capacidade residual funcional, evitando o colapso alveolar?", options: ["Gemido expiratório.", "Batimento de asa de nariz.", "Taquipneia.", "Retração subdiafragmática."], correctIndex: 0 },
  { id: "unifesp_2024_100", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 3 anos de idade, com doença falciforme, há dois dias apresenta dor abdominal, medicado em casa com dipirona, sem melhora, progredindo para nota 9 em escala de dor, necessitando de morfina. Exame físico: febre e desconforto respiratório. Exame laboratorial: Hb = 9,8 g/dL. Além de realizar raio X de tórax, qual é a próxima conduta mais adequada?", options: ["Transfusão de hemácias.", "Prescrever antibiótico.", "Hidratação endovenosa.", "Corticóide inalatório."], correctIndex: 1 },
];
